def match(pattern: str, text: str) -> bool:
    class Parser:
        def __init__(self, p):
            self.p = p
            self.idx = 0

        def parse(self):
            return self.parse_alternation()

        def parse_alternation(self):
            options = [self.parse_sequence()]
            while self.idx < len(self.p) and self.p[self.idx] == '|':
                self.idx += 1
                options.append(self.parse_sequence())
            if len(options) == 1:
                return options[0]
            return ('alternation', options)

        def parse_sequence(self):
            items = []
            while self.idx < len(self.p) and self.p[self.idx] not in ')|':
                items.append(self.parse_item())
            return ('sequence', items)

        def parse_item(self):
            atom = self.parse_atom()
            if self.idx < len(self.p) and self.p[self.idx] in '*+?':
                quant = self.p[self.idx]
                self.idx += 1
                if quant == '*':
                    return ('quantified', atom, 0, float('inf'))
                elif quant == '+':
                    return ('quantified', atom, 1, float('inf'))
                else:
                    return ('quantified', atom, 0, 1)
            return atom

        def parse_atom(self):
            ch = self.p[self.idx]
            if ch == '.':
                self.idx += 1
                return ('dot',)
            elif ch == '[':
                self.idx += 1
                negated = self.idx < len(self.p) and self.p[self.idx] == '^'
                if negated:
                    self.idx += 1
                chars = set()
                while self.idx < len(self.p) and self.p[self.idx] != ']':
                    start = self.p[self.idx]
                    self.idx += 1
                    if (self.idx < len(self.p) and self.p[self.idx] == '-' and 
                        self.idx + 1 < len(self.p) and self.p[self.idx + 1] != ']'):
                        self.idx += 1
                        end = self.p[self.idx]
                        self.idx += 1
                        for i in range(ord(start), ord(end) + 1):
                            chars.add(chr(i))
                    else:
                        chars.add(start)
                self.idx += 1
                return ('charclass', negated, chars)
            elif ch == '(':
                self.idx += 1
                expr = self.parse_alternation()
                self.idx += 1
                return ('group', expr)
            else:
                self.idx += 1
                return ('literal', ch)

    parser = Parser(pattern)
    parsed = parser.parse()

    def matches(expr, start):
        expr_type = expr[0]

        if expr_type == 'literal':
            if start < len(text) and text[start] == expr[1]:
                return {start + 1}
            return set()

        elif expr_type == 'dot':
            if start < len(text):
                return {start + 1}
            return set()

        elif expr_type == 'charclass':
            _, negated, chars = expr
            if start < len(text):
                in_class = text[start] in chars
                if (in_class and not negated) or (not in_class and negated):
                    return {start + 1}
            return set()

        elif expr_type == 'group':
            return matches(expr[1], start)

        elif expr_type == 'quantified':
            _, atom, min_count, max_count = expr
            results = set()
            positions = {start}

            if min_count <= 0:
                results.update(positions)

            count = 0
            while count < max_count and positions:
                next_positions = set()
                for pos in positions:
                    next_positions.update(matches(atom, pos))
                if not next_positions:
                    break
                count += 1
                positions = next_positions
                if count >= min_count:
                    results.update(positions)

            return results

        elif expr_type == 'sequence':
            positions = {start}
            for item in expr[1]:
                new_positions = set()
                for pos in positions:
                    new_positions.update(matches(item, pos))
                positions = new_positions
                if not positions:
                    break
            return positions

        elif expr_type == 'alternation':
            results = set()
            for option in expr[1]:
                results.update(matches(option, start))
            return results

        return set()

    endings = matches(parsed, 0)
    return len(text) in endings
